import { defineConfig } from 'vitest/config';

/**
 * E2E test configuration.
 *
 * Uses node environment (native fetch in Node 22) and targets tests under tests/e2e/.
 * Run explicitly: npx vitest run tests/e2e/ --config tests/e2e/e2e.config.ts
 */
export default defineConfig({
	test: {
		environment: 'node',
		include: ['tests/e2e/**/*.test.ts'],
		testTimeout: 15_000,
		hookTimeout: 10_000,
		reporters: ['default', 'verbose'],
		outputFile: {
			json: 'tests/e2e/results.json'
		}
	}
});

/**
 * E2E test helpers — shared configuration and API client utilities.
 *
 * Uses native Node.js fetch (Node 22+). No external HTTP libraries needed.
 */

// ── Configuration ────────────────────────────────────────────────────────────

export const E2E_BASE_URL = process.env.E2E_BASE_URL || 'http://172.18.200.47:30002';
export const E2E_ADMIN_PASSWORD = process.env.E2E_ADMIN_PASSWORD || 'admin123';
export const E2E_API_KEY = process.env.E2E_API_KEY || 'dev-api-key-2025';

// ── Types ────────────────────────────────────────────────────────────────────

export interface HealthResponse {
	status: 'ok';
	version: string;
	uptime: number;
	db: 'connected' | 'error';
}

export interface LoginResponse {
	token: string;
}

export interface MilestoneResponse {
	id: string;
	title: string;
	sourceMd: string | null;
	gitUrl: string | null;
	status: 'draft' | 'in-progress' | 'completed' | 'archived';
	createdAt: string;
}

export interface ApiError {
	error: string;
	message: string;
	details?: Array<{ field: string; message: string }>;
}

// ── API Client ───────────────────────────────────────────────────────────────

/** Perform an authenticated request using the session token from login. */
export async function api(
	path: string,
	options: RequestInit & { token?: string } = {}
): Promise<{ status: number; body: unknown; headers: Headers }> {
	const { token, ...fetchOptions } = options;
	const headers = new Headers(fetchOptions.headers);

	if (token) {
		headers.set('Authorization', `Bearer ${token}`);
	}
	if (!headers.has('Content-Type') && fetchOptions.body) {
		headers.set('Content-Type', 'application/json');
	}

	const url = `${E2E_BASE_URL}${path}`;
	const res = await fetch(url, { ...fetchOptions, headers });

	let body: unknown;
	const contentType = res.headers.get('content-type') ?? '';
	if (contentType.includes('application/json')) {
		body = await res.json();
	} else {
		body = await res.text();
	}

	return { status: res.status, body, headers: res.headers };
}

/** Login and return the session token. Throws on non-200. */
export async function login(password: string = E2E_ADMIN_PASSWORD): Promise<string> {
	const { status, body } = await api('/api/auth/login', {
		method: 'POST',
		body: JSON.stringify({ password })
	});

	if (status !== 200 || typeof body !== 'object' || body === null || !('token' in body)) {
		throw new Error(`Login failed: status=${status}, body=${JSON.stringify(body)}`);
	}

	return (body as LoginResponse).token;
}

/**
 * E2E tests — Health check endpoint.
 *
 * GET /api/health should return 200 with { status, version, uptime, db }.
 */
import { describe, it, expect } from 'vitest';
import { api, type HealthResponse } from './helpers.js';

describe('GET /api/health', () => {
	it('returns 200 with ok status', async () => {
		const { status, body } = await api('/api/health');

		expect(status).toBe(200);
		expect(body).toMatchObject({
			status: 'ok',
			db: 'connected'
		});

		const health = body as HealthResponse;
		expect(typeof health.version).toBe('string');
		expect(typeof health.uptime).toBe('number');
		expect(health.uptime).toBeGreaterThan(0);
	});

	it('responds quickly (under 5s)', async () => {
		const start = performance.now();
		const { status } = await api('/api/health');
		const elapsed = performance.now() - start;

		expect(status).toBe(200);
		expect(elapsed).toBeLessThan(5_000);
	});
});

/**
 * E2E tests — Login and API authentication.
 *
 * Covers:
 * - Login with valid password → 200 + token
 * - Login with invalid password → 401
 * - API access with Bearer token → 200
 * - API access without token → 401
 * - API access with invalid token → 401
 */
import { describe, it, expect, beforeAll } from 'vitest';
import { api, login, E2E_ADMIN_PASSWORD, type MilestoneResponse } from './helpers.js';

describe('Auth', () => {
	describe('POST /api/auth/login', () => {
		it('returns 200 and token for valid password', async () => {
			const { status, body } = await api('/api/auth/login', {
				method: 'POST',
				body: JSON.stringify({ password: E2E_ADMIN_PASSWORD })
			});

			expect(status).toBe(200);
			expect(body).toHaveProperty('token');
			expect(typeof (body as { token: string }).token).toBe('string');
			expect((body as { token: string }).token.length).toBeGreaterThan(10);
		});

		it('returns 401 for invalid password', async () => {
			const { status, body } = await api('/api/auth/login', {
				method: 'POST',
				body: JSON.stringify({ password: 'wrong-password' })
			});

			expect(status).toBe(401);
			expect(body).toMatchObject({
				error: 'unauthorized'
			});
		});

		it('returns 400 for missing password', async () => {
			const { status, body } = await api('/api/auth/login', {
				method: 'POST',
				body: JSON.stringify({})
			});

			expect(status).toBe(400);
			expect(body).toMatchObject({
				error: 'validation_error'
			});
		});
	});

	describe('API auth (Bearer token)', () => {
		let token: string;

		beforeAll(async () => {
			token = await login();
		});

		it('grants access to GET /api/milestones with valid token', async () => {
			const { status, body } = await api('/api/milestones', { token });

			expect(status).toBe(200);
			expect(Array.isArray(body)).toBe(true);
		});

		it('returns 401 for GET /api/milestones without token', async () => {
			const { status, body } = await api('/api/milestones');

			expect(status).toBe(401);
			expect(body).toMatchObject({
				error: 'unauthorized'
			});
		});

		it('returns 401 for GET /api/milestones with invalid token', async () => {
			const { status, body } = await api('/api/milestones', {
				token: 'invalid-token-12345'
			});

			expect(status).toBe(401);
			expect(body).toMatchObject({
				error: 'unauthorized'
			});
		});
	});
});

/**
 * E2E tests — Core business flow.
 *
 * Full lifecycle: Create milestone → GET by ID → PATCH status → verify updated status.
 */
import { describe, it, expect, beforeAll } from 'vitest';
import { api, login, type MilestoneResponse } from './helpers.js';

describe('Core business flow', () => {
	let token: string;
	let createdId: string;

	beforeAll(async () => {
		token = await login();
	});

	it('creates a milestone (POST /api/milestones)', async () => {
		const { status, body } = await api('/api/milestones', {
			method: 'POST',
			token,
			body: JSON.stringify({
				title: `E2E Test Milestone ${Date.now()}`
			})
		});

		expect(status).toBe(201);
		const milestone = body as MilestoneResponse;
		expect(milestone).toHaveProperty('id');
		expect(milestone.title).toContain('E2E Test Milestone');
		expect(milestone.status).toBe('draft');

		createdId = milestone.id;
	});

	it('gets the milestone by ID (GET /api/milestones/:id)', async () => {
		expect(createdId).toBeDefined();

		const { status, body } = await api(`/api/milestones/${createdId}`, { token });

		expect(status).toBe(200);
		const milestone = body as MilestoneResponse;
		expect(milestone.id).toBe(createdId);
		expect(milestone.status).toBe('draft');
	});

	it('updates milestone status to in-progress (PATCH /api/milestones/:id)', async () => {
		const { status, body } = await api(`/api/milestones/${createdId}`, {
			method: 'PATCH',
			token,
			body: JSON.stringify({ status: 'in-progress' })
		});

		expect(status).toBe(200);
		const milestone = body as MilestoneResponse;
		expect(milestone.id).toBe(createdId);
		expect(milestone.status).toBe('in-progress');
	});

	it('reflects the updated status on re-fetch', async () => {
		const { status, body } = await api(`/api/milestones/${createdId}`, { token });

		expect(status).toBe(200);
		const milestone = body as MilestoneResponse;
		expect(milestone.status).toBe('in-progress');
	});

	it('returns 404 for non-existent milestone', async () => {
		const { status, body } = await api('/api/milestones/NON-EXISTENT-999', { token });

		expect(status).toBe(404);
		expect(body).toMatchObject({
			error: 'not_found'
		});
	});

	it('returns 400 for invalid status in PATCH', async () => {
		const { status, body } = await api(`/api/milestones/${createdId}`, {
			method: 'PATCH',
			token,
			body: JSON.stringify({ status: 'invalid-status' })
		});

		expect(status).toBe(400);
		expect(body).toMatchObject({
			error: 'validation_error'
		});
	});
});
